import{_ as a,r as c,o as r,e as l,l as t,x as i,w as n,F as d,g as e,E as s}from"./app.a050b316.js";var u="/images/annotation/confirmation/confirmation.png",p="/images/annotation/confirmation/confirmation_table.png",m="/images/annotation/confirmation/condition_1.png",h="/images/annotation/confirmation/condition_2.png",f="/images/annotation/confirmation/confirmation_condition_explicit.png",v="/images/annotation/confirmation/confirmation_expression.png",g="/images/annotation/confirmation/confirmation_condition_implicit.png";const _={},y=t("h1",{id:"confirmation",tabindex:"-1"},[t("a",{class:"header-anchor",href:"#confirmation","aria-hidden":"true"},"#"),e(" Confirmation")],-1),w={class:"table-of-contents"},b=e("Motivation"),x=e("Overview"),k=e("How to use"),I=e("Conditions"),B=e("Explicit"),q=e("Implicit"),C=s('<h2 id="motivation" tabindex="-1"><a class="header-anchor" href="#motivation" aria-hidden="true">#</a> Motivation</h2><p>During ordering a spicy sandwich, user might indicate a spicy level that might be too strong for many people,</p><div class="custom-container conversation"><div class="custom-container bot"><p class="custom-container-title">Bot</p><p>How spicy do you want for your Tofu sandwich? On scale of 1 to 5?</p></div><div class="custom-container user"><p class="custom-container-title">User</p><p>5 please?</p></div><div class="custom-container bot"><p class="custom-container-title">Bot</p><p>We use strong Jalape\xF1o, so level 5 is considered deadly, are you sure you want level 5?</p></div></div><h2 id="overview" tabindex="-1"><a class="header-anchor" href="#overview" aria-hidden="true">#</a> Overview</h2><p>Even when user&#39;s choice for a slot passes value check, business can still think there are things that user might not know, thus can inform user something (implicit confirmation) or ask user to confirm their choice (explicit confirmation).</p><p>With confirmation, you can control this behavior by</p><ul><li>Decide on which types of confirmation: Explicit and Implicit</li><li>Specify a conditional under when confirmations should be triggered.</li><li>Support multi-valued slot confirmation via per value confirmed</li><li>Provide corrections on default strategy and interruption strategy</li><li>Provide the way to customize the &quot;yes/no&quot; understanding of user utterances under this context for explicit confirmations</li></ul><h2 id="how-to-use" tabindex="-1"><a class="header-anchor" href="#how-to-use" aria-hidden="true">#</a> How to use</h2><div class="custom-container thumbnail"><p><img src="'+u+'" alt="confirmation"></p></div><p>Confirmation is an optional annotation. There are two places that you can define confirmation: slot level and frame level, different places have different meanings:</p><ul><li><strong>Slot Level</strong>: bot will confirm on each slot which is defined.</li><li><strong>Frame Level</strong>: bot will confirm after all slots on the frame have been done, just like bundle slots together for confirmation. User can accept and modify batch confirmations.</li></ul><h3 id="conditions" tabindex="-1"><a class="header-anchor" href="#conditions" aria-hidden="true">#</a> Conditions</h3>',12),U=e("With condition, bot can confirm with the user when the set of conditions are met. You can use "),E=e("kotlin Expression"),A=e(" to express the timing of key pieces of information that should be implied or requested."),N=s('<div class="custom-container conversation"><div class="custom-container user"><p class="custom-container-title">User</p><p>Get me two tickets for Adele on Jul 1st</p></div><div class="custom-container bot"><p class="custom-container-title">Bot</p><p>Adele on Jul 1st, the Event Organizer is requiring all attendees to have been fully vaccinated (14 days past final vaccination show) AND to have received a negative COVID-19 test within 48 hours of the event. Please confirm you want to continue?</p></div><div class="custom-container user"><p class="custom-container-title">User</p><p>confirm</p></div><div class="custom-container bot"><p class="custom-container-title">Bot</p><p>Please select your seats</p></div></div><p>From the example above, you can see that bot will confirm the COVID-19 info and request a yes or no answer when the artist is Adele, while others will not:</p><div class="custom-container conversation"><div class="custom-container user"><p class="custom-container-title">User</p><p>Get me two tickets for Coldplay on Aug 16th</p></div><div class="custom-container bot"><p class="custom-container-title">Bot</p><p>Coldplay on Aug 16th, please select your seats</p></div></div><p>In this case, there are multiple conditions that need to be set here:</p><div class="custom-container thumbnail"><p><img src="'+p+'" alt="multiple conditions"></p></div><ul><li>One should like <code>artist.identifier() == &quot;adele&quot;</code> :</li></ul><div class="custom-container thumbnail"><p><img src="'+m+'" alt="condition"></p></div><ul><li>Another can be simple, like <code>artist != null</code>:</li></ul><div class="custom-container thumbnail"><p><img src="'+h+'" alt="condition"></p></div><p>Bot will check the conditions according to the top-to-bottom order, and confirm when the condition is met:</p><ul><li>If the first condition is <code>true</code>, bot will respond the confirmation to the user.</li><li>if the first condition is <code>false</code>, bot will move on to the next condition, and so on.</li></ul>',11),S=e("Know more about "),O=e("kotlin Expression"),F=e("."),V=s('<h3 id="explicit" tabindex="-1"><a class="header-anchor" href="#explicit" aria-hidden="true">#</a> Explicit</h3><div class="custom-container thumbnail"><p><img src="'+f+'" alt="explicit"></p></div><p>Explicit confirmation typically involves checking with the user that their input or request was understood correctly, it is very wise to confirm the critical details. Bot will not perform the action until it gets the reply from the user to confirm, usually yes/no or some synonym.</p><p>You can double-check with the user prior to performing an action that would be difficult to undo, for example, cancel an order:</p><div class="custom-container conversation"><div class="custom-container user"><p class="custom-container-title">User</p><p>Can I cancel an order?</p></div><div class="custom-container bot"><p class="custom-container-title">Bot</p><p>Sure. Could you provide me with the order number?</p></div><div class="custom-container user"><p class="custom-container-title">User</p><p>123456</p></div><div class="custom-container bot"><p class="custom-container-title">Bot</p><p>I found the order: <em>[order details]</em> <br>Should I go ahead and Cancel the order?</p></div><div class="custom-container user"><p class="custom-container-title">User</p><p>Yes.</p></div><div class="custom-container bot"><p class="custom-container-title">Bot</p><p>I have cancelled the order for you.</p></div></div><p>But there are many ways to say yes or no by the user. To handle the synonym expressions of &quot;yes/no&quot;, <strong>Affirmatives</strong> and <strong>Negatives</strong> provide the way for you to customize the &quot;yes/no&quot; understanding in specific contexts.</p><div class="custom-container thumbnail"><p><img src="'+v+'" alt="implicit"></p></div><p>For example, In some scenarios, &quot;<em>Sorry I need to change</em>&quot; represents a new intention, but in certain scenarios, this means the user says no to the confirm. So you can add all of these cases in <strong>Affirmatives</strong> and <strong>Negatives</strong>.</p><div class="custom-container tip"><p class="custom-container-title">Note</p><p>The common understanding of confirmation yes and no is already supported in <strong>system intent</strong> <em><code>io.framely.core.confirmation.Yes</code></em> and <em><code>io.framely.core.confirmation.No</code></em>, so no need to define it here. But if needed, you can also customize system intent behavior by adding expressions.</p></div><h3 id="implicit" tabindex="-1"><a class="header-anchor" href="#implicit" aria-hidden="true">#</a> Implicit</h3><div class="custom-container thumbnail"><p><img src="'+g+'" alt="implicit"></p></div><p>Unlike explicit confirmation, implicit confirmation does not require a reply from the user. It just simply confirms the input has been received like an FYI notification, and an operation will take place without asking for user approval, although users might give one if they want to make a correction.</p><div class="custom-container conversation"><div class="custom-container user"><p class="custom-container-title">User</p><p>I need to change the shipping address.</p></div><div class="custom-container bot"><p class="custom-container-title">Bot</p><p>Can I get your street address?</p></div><div class="custom-container user"><p class="custom-container-title">User</p><p><em>[address]</em></p></div><div class="custom-container bot"><p class="custom-container-title">Bot</p><p>Get. I will set your street address to be <em>[address]</em> . <br>You will receive an email confirmation of this change in a few minutes. What else can I help you with?</p></div></div>',13);function Y(D,T){const o=c("RouterLink");return r(),l(d,null,[y,t("nav",w,[t("ul",null,[t("li",null,[i(o,{to:"#motivation"},{default:n(()=>[b]),_:1})]),t("li",null,[i(o,{to:"#overview"},{default:n(()=>[x]),_:1})]),t("li",null,[i(o,{to:"#how-to-use"},{default:n(()=>[k]),_:1}),t("ul",null,[t("li",null,[i(o,{to:"#conditions"},{default:n(()=>[I]),_:1})]),t("li",null,[i(o,{to:"#explicit"},{default:n(()=>[B]),_:1})]),t("li",null,[i(o,{to:"#implicit"},{default:n(()=>[q]),_:1})])])])])]),C,t("p",null,[U,i(o,{to:"/reference/annotations/kotlinexpression.html"},{default:n(()=>[E]),_:1}),A]),N,t("p",null,[S,i(o,{to:"/reference/annotations/kotlinexpression.html"},{default:n(()=>[O]),_:1}),F]),V],64)}var L=a(_,[["render",Y],["__file","confirmation.html.vue"]]);export{L as default};
